pub async fn create_user(pool: &sqlx::PgPool, name: &str, email: &str) -> Result<CreateUserRow, sqlx::Error> {
    sqlx::query_as!(CreateUserRow, "INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id", name, email)
        .fetch_one(pool)
        .await
}

